**Problem 1:**

Create a function file `aboda_final_p1.m`:

```matlab
function [D, Q, iter] = aboda_final_p1(A, tol)
    n = size(A, 1);
    Q = eye(n); % Initialize unitary transformation matrix
    iter = 0; % Initialize iteration count
    while 1
        [Qk, Rk] = qr(A); % QR decomposition
        A = Rk * Qk; % Update A
        Q = Q * Qk; % Update transformation matrix
        iter = iter + 1; % Increment iteration count
        Tk_1 = diag(A, -1);
        Tk_0 = diag(A);
        if norm(Tk_1, 2) < tol * norm(Tk_0, 2)
            break; % Convergence has been achieved
        end
    end
    D = A; % Eigenvalues are on the diagonal of the resulting A
end
```

**Problem 2:**

Create a function file `aboda_final_p2.m`:

```matlab
function [D, Q, iter] = aboda_final_p2(A, tol)
    n = size(A, 1);
    Q = eye(n); % Initialize transformation matrix
    iter = 0; % Initialize iteration count
    while 1
        B = A([n-1, n], [n-1, n]);
        d = eig(B); % Eigenvalues of lower-right 2x2 portion
        [~, idx] = min(abs(d - B(2,2)));
        mu = d(idx); % Wilkinson shift
        A_shifted = A - mu * eye(n);
        [Qk, Rk] = qr(A_shifted);
        A = Rk * Qk + mu * eye(n); % Update A
        Q = Q * Qk; % Update transformation matrix
        iter = iter + 1; % Increment iteration count
        Tk_1 = diag(A, -1);
        Tk_0 = diag(A);
        if norm(Tk_1, 2) < tol * norm(Tk_0, 2)
            break; % Convergence has been achieved
        end
    end
    D = A; % Eigenvalues are on the diagonal of the resulting A
end
```

**Problem 3:**

Create a function file `aboda_final_p3.m`:

```matlab
function [mu, var] = aboda_final_p3(eigFunc, m, tol, N)
    iterations = zeros(N, 1);
    rng(0); % Set random seed to 0
    for i = 1:N
        A = rand(m);
        A = 0.5 * (A + A'); % Make the matrix symmetric
        [~, ~, iter] = eigFunc(A, tol);
        iterations(i) = iter;
    end
    mu = mean(iterations);
    var = var(iterations);
end
```

